import React from "react"
import { Link } from "gatsby"
import { Layout } from "../components/Layout"
import { Seo } from "../components/Seo"

export default function HomePage() {
  return (
    <Layout title="Case study form CRM">
      <Seo title="Home" />
      <p className="muted" style={{ maxWidth: 640 }}>
        Dynamic React forms with a live preview, saved submissions via a small API, and an admin screen to
        export a standalone <code>.js</code> component file that uses your shared UI primitives.
      </p>
      <div className="stack" style={{ marginTop: 24 }}>
        <div className="panel">
          <h2 style={{ marginTop: 0 }}>User</h2>
          <p className="muted">Fill a form and see the preview update as you type. Saves draft to the server (submission id is remembered in the browser).</p>
          <Link className="btn btn-primary" style={{ display: "inline-block" }} to="/form/demo-case-study">
            Open demo form
          </Link>
        </div>
        <div className="panel">
          <h2 style={{ marginTop: 0 }}>Admin</h2>
          <p className="muted">Create or edit form definitions, list submissions, and download generated component code.</p>
          <Link className="btn btn-primary" style={{ display: "inline-block" }} to="/admin">
            Open admin
          </Link>
        </div>
      </div>
    </Layout>
  )
}
